import React, { useState } from 'react';
import { useBlockchain } from '../context/BlockchainContext';

const AdminDashboard: React.FC = () => {
    const { isAdmin, contract } = useBlockchain();
    const [verifierAddress, setVerifierAddress] = useState('');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    if (!isAdmin) {
        return <div style={{ padding: '2rem', textAlign: 'center', color: 'red' }}>Access Denied: Only Admin can access this page.</div>;
    }

    const handleAddVerifier = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!contract || !verifierAddress) return;

        setLoading(true);
        setMessage('');
        try {
            const tx = await contract.addVerifier(verifierAddress);
            await tx.wait();
            setMessage(`Successfully added ${verifierAddress} as a verifier.`);
            setVerifierAddress('');
        } catch (error: any) {
            setMessage(`Error adding verifier: ${error.message || error}`);
        } finally {
            setLoading(false);
        }
    };

    const handleRemoveVerifier = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!contract || !verifierAddress) return;

        setLoading(true);
        setMessage('');
        try {
            const tx = await contract.removeVerifier(verifierAddress);
            await tx.wait();
            setMessage(`Successfully removed ${verifierAddress} as a verifier.`);
            setVerifierAddress('');
        } catch (error: any) {
            setMessage(`Error removing verifier: ${error.message || error}`);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ padding: '2rem', maxWidth: '600px', margin: '0 auto' }}>
            <h2>Admin Dashboard</h2>
            <p>Welcome Admin. You can manage verifiers here.</p>

            <div style={{ padding: '1.5rem', border: '1px solid #ccc', borderRadius: '8px', marginTop: '2rem' }}>
                <h3>Manage Verifiers</h3>

                {message && (
                    <div style={{ padding: '1rem', marginBottom: '1rem', backgroundColor: message.includes('Error') ? '#ffebee' : '#e8f5e9', borderRadius: '4px' }}>
                        {message}
                    </div>
                )}

                <form style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                    <div>
                        <label style={{ display: 'block', marginBottom: '0.5rem' }}>Verifier Ethereum Address:</label>
                        <input 
                            type="text" 
                            value={verifierAddress}
                            onChange={(e) => setVerifierAddress(e.target.value)}
                            placeholder="0x..."
                            style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc' }}
                            required
                        />
                    </div>
                    <div style={{ display: 'flex', gap: '1rem' }}>
                        <button 
                            type="button" 
                            onClick={handleAddVerifier}
                            disabled={loading || !verifierAddress}
                            style={{ flex: 1, padding: '0.75rem', backgroundColor: '#4caf50', color: 'white', border: 'none', borderRadius: '4px', cursor: loading ? 'not-allowed' : 'pointer' }}
                        >
                            {loading ? 'Processing...' : 'Add Verifier'}
                        </button>
                        <button 
                            type="button" 
                            onClick={handleRemoveVerifier}
                            disabled={loading || !verifierAddress}
                            style={{ flex: 1, padding: '0.75rem', backgroundColor: '#f44336', color: 'white', border: 'none', borderRadius: '4px', cursor: loading ? 'not-allowed' : 'pointer' }}
                        >
                            {loading ? 'Processing...' : 'Remove Verifier'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default AdminDashboard;
